prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "38b17e822a5e4307ae051694293e4d0f" .

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  FILTER(
    CONTAINS(LCASE(STR(?taskName)), "financ") ||
    CONTAINS(LCASE(STR(?taskName)), "payment") ||
    CONTAINS(LCASE(STR(?taskName)), "invoice") ||
    CONTAINS(LCASE(STR(?taskName)), "bank") ||
    CONTAINS(LCASE(STR(?taskName)), "loan")
  )
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?taskName WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "38b17e822a5e4307ae051694293e4d0f" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .
  FILTER( ?taskName != "" )
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?org ?orgId ?modelsCount WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId ?orgId .
  FILTER(STR(?orgId) = "38b17e822a5e4307ae051694293e4d0f")
  {
    SELECT (COUNT(DISTINCT ?model) AS ?modelsCount) WHERE {
      ?model a bboExt:Model ;
             tai:belongsTo ?org .
    }
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?model ?modelName WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "38b17e822a5e4307ae051694293e4d0f" .

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  OPTIONAL { ?task bbo:name ?taskName . }
  FILTER(BOUND(?taskName) && STR(?taskName) != "")
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?taskComment ?modelName WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "38b17e822a5e4307ae051694293e4d0f" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?container .

  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task rdfs:comment ?taskComment . }

  ?container tai:belongsTo ?model .
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?container ?containerType ?modelName ?orgId WHERE {
  ?task a bboExt:ChoreographyTask .
  OPTIONAL { ?task bbo:name ?taskName . }

  OPTIONAL {
    ?task tai:belongsTo ?container .
    OPTIONAL { ?container a ?containerType . }
    OPTIONAL {
      ?container tai:belongsTo ?model .
      OPTIONAL { ?model bbo:name ?modelName . }
    }
    OPTIONAL {
      ?model tai:belongsTo ?org .
      OPTIONAL { ?org tai:organizationId ?orgId . }
    }
  }

  FILTER(BOUND(?orgId) && STR(?orgId) = "38b17e822a5e4307ae051694293e4d0f")
}
LIMIT 25
